Here are the public test cases for feature2_1_resolve_name:
{
  "description": "Resolve a name to its address list using the perspective of a requesting container IP. The requester's network membership is derived from configuration; the queried name may be the requester's own name, another container's primary name, or one of its aliases. The result is the ordered list of addresses registered for that name on the requester's network.",
  "cases": [
    {
      "input": {
        "op": "lookup",
        "config": {
          "net0": "10.88.0.1\n68fb291b0318b54a71f6f3636e58bd0896f084e5ba4fa311ecf36e019c5e6e43 10.88.0.2  condescendingnash\n68fb291b0318b54a71f6f3636e58bd0896f084e5ba4fa311ecf36e019c5e6e48 10.88.0.5  HelloWorld\n95655fb6832ba134efa66e9c80862a6c9b04f3cc6abf8adfdda8c38112c2c6fa 10.88.0.3  hopefulmontalcini,testdbctr\n8bcc5fe0cb09bee5dfb71d61503a87688cfc82aa5f130bcedb19357a17765926 10.88.0.4  trustingzhukovsky,ctr1,ctra\n"
        },
        "requester": "10.88.0.2",
        "name": "condescendingnash"
      },
      "expected_output": "addresses=10.88.0.2\n"
    },
    {
      "input": {
        "op": "lookup",
        "config": {
          "net0": "10.88.0.1\n68fb291b0318b54a71f6f3636e58bd0896f084e5ba4fa311ecf36e019c5e6e43 10.88.0.2  condescendingnash\n68fb291b0318b54a71f6f3636e58bd0896f084e5ba4fa311ecf36e019c5e6e48 10.88.0.5  HelloWorld\n95655fb6832ba134efa66e9c80862a6c9b04f3cc6abf8adfdda8c38112c2c6fa 10.88.0.3  hopefulmontalcini,testdbctr\n8bcc5fe0cb09bee5dfb71d61503a87688cfc82aa5f130bcedb19357a17765926 10.88.0.4  trustingzhukovsky,ctr1,ctra\n"
        },
        "requester": "10.88.0.2",
        "name": "trustingzhukovsky"
      },
      "expected_output": "addresses=10.88.0.4\n"
    }
  ]
}

